Here's a complete implementation:

**XAML ‚Äî `ItemsPage.xaml`**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:DataType="vm:ItemsViewModel"
             x:Class="MyApp.Views.ItemsPage">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                        <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel ‚Äî `ItemsViewModel.cs`**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false;   // Must set false or spinner stays
        }
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage), new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });

        CurrentItem = null;  // Reset so the same item can be re-selected
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---|---|
| `IsRefreshing` ‚Üí `bool` | Controls the refresh spinner; **must be set to `false`** when done |
| `Command` ‚Üí `RefreshCommand` | Fires when user pulls down |
| `SelectionMode="Single"` | Enables single-tap selection |
| `SelectedItem` ‚Üí `CurrentItem` (`TwoWay`) | Tracks the selected item |
| `SelectionChangedCommand` | Fires on selection change to trigger navigation |

**Important rules:**
- Use `ObservableCollection<T>`, never `List<T>` ‚Äî otherwise the UI won't update.
- Set `x:DataType` on both the page and the `DataTemplate` for compiled bindings.
- Reset `CurrentItem = null` after navigation so the same item can be re-selected.
- Never use `ViewCell` inside a `CollectionView` template ‚Äî use a `Grid` or `StackLayout` as the root.
